import React from 'react';
import './About.css'; // Optional: Add some styling for this page

function About() {
  return (
    <div className="about-container">
      {/* Header for About Me Section */}
      <h1>About Me</h1>

      {/* Paragraphs with content */}
      <p>
        Hi, I'm Shreya Banwaskar, a passionate front-end web developer with a strong focus on building visually appealing and functional websites.
        I specialize in creating responsive, user-friendly applications that deliver a great user experience.
      </p>

      <p>
        I have experience working with modern technologies like React, JavaScript, HTML, and CSS. 
        I enjoy turning complex problems into simple, beautiful, and intuitive designs.
      </p>

      <p>
        Apart from coding, I love exploring new technologies, learning about design patterns, and staying up to date with the latest trends in web development.
        In my spare time, I also enjoy reading, traveling, and contributing to open-source projects.
      </p>
    </div>
  );
}

export default About;
